/* eslint-disable @typescript-eslint/no-magic-numbers */
import chroma from 'chroma-js';
import minBy from 'lodash/minBy';
import PresetColorsLarkLight from '../preset-colors/light';
import type { PresetColor } from '../types';

const between = (a: number, min: number, max: number) => Math.min(Math.max(a, min), max);

const presetColors = PresetColorsLarkLight;

export default function ({
  brandColor = PresetColorsLarkLight[0].colors[6].value,
}: {
  brandColor?: string;
} = {}): PresetColor[] {
  const chromaBrandColor = chroma(brandColor);
  const chromaColors = presetColors
    .map(o => o.colors[6].value)
    .flat()
    .map(o => chroma(o));
  const closestColor = minBy(chromaColors, c => chroma.deltaE(c, chromaBrandColor));
  if (!closestColor) {
    return presetColors;
  }

  const [h1, s1, v1] = closestColor.hsv();
  const [h2, s2, v2] = chromaBrandColor.hsv();
  const [dh, ds, dv] = [between(h2 - h1, -10, 10), between(s2 - s1, -0.1, 0.1), between(v2 - v1, -0.1, 0.1)];

  const getNewColor = (color: string | chroma.Color) => {
    const chromaColor = chroma(color);
    const [h, s, v] = chromaColor.hsv();
    const newColor = chromaColor
      .set('hsv.h', (h + dh + 360) % 360)
      .set('hsv.s', s + ds)
      .set('hsv.v', v + dv);
    return newColor;
  };

  return presetColors.map(({ key, colors }) => {
    const newColors = colors.map(({ level, value }) => ({
      level,
      value: getNewColor(value).hex(),
    }));
    return {
      key,
      colors: newColors,
    };
  });
}
